import{_ as a,o as t,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable TikTok Advanced SAN","description":"","frontmatter":{"title":"Enable TikTok Advanced SAN","slug":"enable-tiktok-advanced-san"},"headers":[],"relativePath":"marketer-hub/enable-tiktok-advanced-san.md","filePath":"marketer-hub/enable-tiktok-advanced-san.md"}'),r={name:"marketer-hub/enable-tiktok-advanced-san.md"};function i(s,e,d,l,c,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch&#39;s support for TikTok&#39;s Advanced SAN modules means Branch will send <strong>both</strong> ad link and SAN attribution decision results to TikTok, instead of just the latter. This latest approach maximizes your attribution coverage and prioritizing SAN claims. By gaining access to full Ad Link and TikTok SAN attribution coverage, you get more accurate insights across your campaigns.</p><p>To take full advantage of TikTok’s Advanced SAN, you’ll need to use their SAN module, which provides expanded, precise attribution data. Learn more about TikTok&#39;s transition to a SAN integration model <a href="https://ads.tiktok.com/help/article/about-self-attribution-transition" target="_blank" rel="noreferrer">here</a>.</p><p>Additionally, to achieve optimal attribution coverage with TikTok Advanced SAN, we recommend enabling <a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a>, which increases iOS attribution coverage in a privacy-centric manner.</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>For some accounts, no change is needed to enable Advanced SAN. For these accounts, Advanced SAN could be auto-enabled because the correct TikTok app ID was provided in the account&#39;s Branch Dashboard prior to Branch&#39;s support of this module.</p><p>However, if the value was missing or incorrect, then Advanced SAN might need some light manual configuration to be enabled.</p><h3 id="new-apps" tabindex="-1">New apps <a class="header-anchor" href="#new-apps" aria-label="Permalink to &quot;New apps&quot;">​</a></h3><p>If you have a new app, you first need to connect it to TikTok&#39;s Ads Manager using the instructions <a href="https://ads.tiktok.com/help/article/how-to-check-if-your-app-is-on-san-integration" target="_blank" rel="noreferrer">here</a>. Select <strong>Branch</strong> in the MMP section. Then move on to the <a href="./enable-tiktok-advanced-san.html#manual-configuration">configuration steps</a> in this guide.</p><h3 id="auto-enabled" tabindex="-1">Auto-enabled <a class="header-anchor" href="#auto-enabled" aria-label="Permalink to &quot;Auto-enabled&quot;">​</a></h3><p>If Advanced SAN is auto-enabled for your account, it means that TikTok has automatically backfilled your Branch Key in the TikTok Events Manager. Your Branch Key is required to ensure Advanced SAN support. We highly recommend verifying the Branch Key to ensure the correct one has been implemented.</p><p>You can check whether your app is on TikTok&#39;s SAN integration using the instructions <a href="https://ads.tiktok.com/help/article/how-to-check-if-your-app-is-on-san-integration" target="_blank" rel="noreferrer">here</a>.</p><p>Continue running your TikTok for Business campaigns using either the SAN integration or a Branch Ad Link.</p><h3 id="manual-configuration" tabindex="-1">Manual configuration <a class="header-anchor" href="#manual-configuration" aria-label="Permalink to &quot;Manual configuration&quot;">​</a></h3><p>If Advanced SAN has not been auto-enabled for your account, you can manually configure the set up.</p><h4 id="configuration-steps" tabindex="-1">Configuration steps <a class="header-anchor" href="#configuration-steps" aria-label="Permalink to &quot;Configuration steps&quot;">​</a></h4><p>To enable Advanced SAN:</p><ol><li><p>Visit your Branch Dashboard to ensure that the &quot;TikTok App ID&quot; field is filled out for your app(s):</p><ol><li>In the navigation panel, select <strong>Ads</strong>, then <strong>Partner Management</strong>.</li><li>Search for &quot;TikTok For Business SAN&quot; in the <strong>Ad Partners</strong> search bar and select the result.</li><li>In the <strong>Ad Account Information</strong> section, find your <strong>TikTok App IDs</strong>. If you don&#39;t have these IDs, you will need to <a href="https://ads.tiktok.com/help/article/how-to-generate-a-tiktok-app-id?lang=en" target="_blank" rel="noreferrer">generate them</a> first.</li></ol></li><li><p>Configure your Branch Key in the TikTok Events Manager:</p><ol><li><p>Visit the Account Settings <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">page</a> of your Branch Dashboard.</p></li><li><p>Copy the Branch Key listed there, which starts with <code>key_live_</code>.</p></li><li><p>Follow the instructions <a href="https://ads.tiktok.com/help/article/integrate-to-san-for-new-apps?lang=en" target="_blank" rel="noreferrer">here</a> to transition your app to a SAN integration within TikTok Ads Manager.</p><p>Once inside the TikTok Events Manager, paste your Branch Key into the Partner Token field in the <strong>Edit Tracking</strong> module on the app details page.</p></li><li><p>Click &quot;Confirm&quot; to update the Branch Key.</p></li></ol></li></ol><h2 id="smart-campaigns" tabindex="-1">Smart+ campaigns <a class="header-anchor" href="#smart-campaigns" aria-label="Permalink to &quot;Smart+ campaigns&quot;">​</a></h2><p>Smart+ Campaigns use TikTok&#39;s AI to automate campaign setup, audience targeting, and creative optimization. Instead of manually configuring each element, you provide your goals and creative assets, and TikTok&#39;s system handles the delivery. Smart+ campaigns work differently from manual campaigns, so they also report data differently in Branch.</p><h3 id="campaign-types" tabindex="-1">Campaign types <a class="header-anchor" href="#campaign-types" aria-label="Permalink to &quot;Campaign types&quot;">​</a></h3><p><strong>Manual Campaigns</strong> give you standard reporting down to the individual ad. You won&#39;t see separate creative performance metrics.</p><p><strong>Smart+ Campaigns</strong> skip the ad level entirely and report directly at the creative level. This means you see creative performance but don&#39;t have an intermediate ad level to analyze.</p><p><strong>Upgraded Smart+ Campaigns</strong> provide the most detail with both ad and creative levels. You can see how ads perform overall and how each individual creative within those ads performs. This helps you identify which specific creative assets are driving your best results.</p><p>Learn more about Smart+ Campaigns in <a href="https://ads.tiktok.com/help/article/about-smart-plus-campaign" target="_blank" rel="noreferrer">TikTok’s documentation</a>.</p><h3 id="campaign-data-breakdown" tabindex="-1">Campaign data breakdown <a class="header-anchor" href="#campaign-data-breakdown" aria-label="Permalink to &quot;Campaign data breakdown&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>Campaign Type</strong></th><th><strong>Account</strong></th><th><strong>Campaign</strong></th><th><strong>Ad Set</strong></th><th><strong>Ad</strong></th><th><strong>Creative</strong></th></tr></thead><tbody><tr><td><strong>Manual Campaigns</strong></td><td>account</td><td>campaign</td><td>adgroup</td><td>ad</td><td>N/A</td></tr><tr><td><strong>Smart+ Campaigns</strong></td><td>account</td><td>campaign</td><td>adgroup</td><td>creative</td><td>N/A (Mapped to Ad, not tracked separately)</td></tr><tr><td><strong>Upgraded Smart+ Campaigns</strong></td><td>account</td><td>campaign</td><td>adgroup</td><td>ad</td><td>creative</td></tr></tbody></table><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Can I use both the Advanced SAN and non-SAN modules from TikTok?</summary><p>Please note that beginning February 1, 2025, Branch will be <strong>discontinuing support</strong> for TikTok’s non-SAN module.</p><p>Branch recommends that customers enable Advanced SAN prior to the discontinuation of the non-SAN module. We also recommend that you start using SAN Ad Links instead of non-SAN Ad Links</p></details><details><summary>Will SKAN data be switched over to SAN completely?</summary><p>Yes, Branch will automatically do this once you disable non-SAN Ad Links.</p></details><details><summary>Do advertisers need to supply Ad Links proactively if they are only tracking app events with Branch?</summary><p>They do not need to supply Ad Links for app promotion campaigns, but for non-app campaigns they will need to use SAN Ad Links.</p></details><details><summary>If I enable TikTok Advanced SAN, should I also enable PAM?</summary><p>We recommend using the TikTok Advanced SAN module alongside our in-house iOS aggregate attribution solution <a href="./predictive-aggregate-measurement.html">PAM</a> in order to maximize attribution coverage.</p><p>PAM is part of our <a href="./packaging.html#performance-product">Performance</a> product.</p></details><details><summary>How can I check if my app is on the SAN integration within the TikTok Ads Manager?</summary><p>To confirm that your app is on the SAN integration, use TikTok&#39;s instructions <a href="https://ads.tiktok.com/help/article/how-to-check-if-your-app-is-on-san-integration" target="_blank" rel="noreferrer">here</a>.</p></details>',33)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
